func TestAgentStudio_UpdateAgent(t *testing.T) {
	t.Parallel()

	client, echo := createAgentStudioClient(t)
	_ = echo

	t.Run("updateAgent with minimal parameters", func(t *testing.T) {
		_, err := client.UpdateAgent(client.NewApiUpdateAgentRequest(
			"785b14e4-61a8-4c03-8028-bf2ba3ae85ff",
			agentStudio.NewEmptyAgentConfigUpdate().SetName("updated-agent-name")))
		require.NoError(t, err)

		require.Equal(t, "/1/agents/785b14e4-61a8-4c03-8028-bf2ba3ae85ff", echo.Path)
		require.Equal(t, "PATCH", echo.Method)

		jsonassert.New(t).Assertf(*echo.Body, "%s", `{"name":"updated-agent-name"}`)
	})
	t.Run("updateAgent with all parameters", func(t *testing.T) {
		_, err := client.UpdateAgent(client.NewApiUpdateAgentRequest(
			"785b14e4-61a8-4c03-8028-bf2ba3ae85ff",
			agentStudio.NewEmptyAgentConfigUpdate().
				SetName("updated-agent").
				SetDescription("Updated description").
				SetProviderId("new-provider-id").
				SetModel("gpt-4o").
				SetInstructions("Updated instructions.").
				SetConfig(map[string]any{"temperature": 0.5}).
				SetTools(
					[]agentStudio.ItemsUnion{*agentStudio.StartPartAsItemsUnion(
						agentStudio.NewEmptyStartPart().SetType("start"))}),
		))
		require.NoError(t, err)

		require.Equal(t, "/1/agents/785b14e4-61a8-4c03-8028-bf2ba3ae85ff", echo.Path)
		require.Equal(t, "PATCH", echo.Method)

		jsonassert.New(t).
			Assertf(*echo.Body, "%s", `{"name":"updated-agent","description":"Updated description","providerId":"new-provider-id","model":"gpt-4o","instructions":"Updated instructions.","config":{"temperature":0.5},"tools":[{"type":"start"}]}`)
	})
}

